const MUSCLE_MAP = {
  "Upper Chest": "Upper Chest",
  "Mid/Low Chest": "Mid/Low Chest",
  "Abs": "Abs",
  "Biceps": "Biceps",
  "Quads": "Quads",
  "Abductors": "Abductors",
  "Traps": "Traps",
  "Mid Back": "Mid Back",
  "Lats": "Lats",
  "Erectors": "Erectors",
  "Glutes": "Glutes",
  "Hamstrings": "Hamstrings",
};

export default function ExerciseMuscleVisualization({ exercise }) {
  const [view, setView] = useState("front");

  if (!exercise?.primary_muscle) {
    return null;
  }

  const primarySet = new Set(Array.isArray(exercise.primary_muscle) ? exercise.primary_muscle : [exercise.primary_muscle]);
  const secondarySet = new Set(exercise.secondary_muscles || []);

  const getMuscleColor = (groupId) => {
    const muscleName = MUSCLE_MAP[groupId];
    if (!muscleName) return null;
    
    if (primarySet.has(muscleName)) {
      return "#FF5E5E";
    } else if (secondarySet.has(muscleName)) {
      return "rgba(255, 94, 94, 0.5)";
    }
    return null;
  };

  const renderGroups = (groups) =>
    Object.entries(groups).map(([id, paths]) => {
      const color = getMuscleColor(id);
      if (!color) return null;
      return (
        <g key={id} fill={color} stroke="none">
          {paths.map((d, i) => <path key={i} d={d} />)}
        </g>
      );
    });

  const containerW = 140;
  const containerH = view === "front"
    ? Math.round(containerW * 1509 / 663)
    : Math.round(containerW * 1500 / 656);

  return (
    <div className="space-y-3">
      <h3 className="text-sm font-semibold">Muscles</h3>
      
      <div className="flex justify-center gap-2 mb-3">
        {["front", "back"].map(v => (
          <button key={v} onClick={() => setView(v)}
            className={`rounded-full font-semibold capitalize transition-all px-3 py-1 text-xs ${
              view === v ? "bg-primary text-white" : "bg-secondary text-muted-foreground"
            }`}>
            {v}
          </button>
        ))}
      </div>

      <div className="flex justify-center">
        <AnimatePresence mode="wait">
          {view === "front" ? (
            <motion.div
              key="front"
              initial={{ opacity: 0, x: -10 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: 10 }}
              transition={{ duration: 0.15 }}
            >
              <svg
                viewBox="0 0 663 1509"
                preserveAspectRatio="xMidYMid meet"
                width={containerW}
                height={containerH}
              >
                <path d={FRONT_BODY_PATH} fill="#7A7A7A" stroke="none" />
                <path d={FRONT_HEAD_PATH} fill="#7A7A7A" stroke="none" />
                {renderGroups(FRONT_GROUPS)}
              </svg>
            </motion.div>
          ) : (
            <motion.div
              key="back"
              initial={{ opacity: 0, x: 10 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -10 }}
              transition={{ duration: 0.15 }}
            >
              <svg
                viewBox="0 0 656 1500"
                preserveAspectRatio="xMidYMid meet"
                width={containerW}
                height={containerH}
              >
                <path d={BACK_BODY_PATH} fill="#7A7A7A" stroke="none" />
                <path d={BACK_HEAD_PATH} fill="#7A7A7A" stroke="none" />
                {renderGroups(BACK_GROUPS)}
              </svg>
            </motion.div>
          )}
        </AnimatePresence>
      </div>

      <div className="flex justify-center gap-4 text-xs">
        <div className="flex items-center gap-1.5">
          <div className="w-3 h-3 rounded-sm" style={{ backgroundColor: "#FF5E5E" }} />
          <span className="text-muted-foreground">Primary</span>
        </div>
        <div className="flex items-center gap-1.5">
          <div className="w-3 h-3 rounded-sm" style={{ backgroundColor: "rgba(255, 94, 94, 0.5)" }} />
          <span className="text-muted-foreground">Secondary</span>
        </div>
      </div>
    </div>
  );
}